require "process.BaseProcess"
require "settlement.ChickenSettlement"
require "config.RespawnConfig"
require "config.SafeAreaConfig"

ChickenProcess = class("ChickenProcess", BaseProcess)

ChickenProcess.Status = {}
ChickenProcess.Status.Init = 0
ChickenProcess.Status.Waitting = 1
ChickenProcess.Status.Prepare = 2
ChickenProcess.Status.Flying = 3
ChickenProcess.Status.FlyingEnd = 4
ChickenProcess.Status.WaitShrink = 5
ChickenProcess.Status.Shrinking = 6
ChickenProcess.Status.WaitSafeArea = 7
ChickenProcess.Status.WaitGameOver = 8
ChickenProcess.Status.GameOver = 9
ChickenProcess.Status.WaitClose = 10
ChickenProcess.curStatus = 0

ChickenProcess.WaitTick = 0
ChickenProcess.PrepareTick = 0
ChickenProcess.WaitFlyingTick = 0
ChickenProcess.WaitShrinkTick = 0
ChickenProcess.WaitShrinkEndTick = 0
ChickenProcess.WaitSafeAreaTick = 0
ChickenProcess.GameOverTick = 0
ChickenProcess.WaitCloseTick = 0
ChickenProcess.RandomWeaponTick = 0
ChickenProcess.curTick = 0

ChickenProcess.IsReviveStage = false

ChickenProcess.poison = {}
ChickenProcess.safe = {}
ChickenProcess.playerTotalNum = 0
ChickenProcess.players = {}
ChickenProcess.Index = 1

function ChickenProcess:onTick(ticks)
    self.curTick = ticks

    if self.curStatus == self.Status.Waitting then
        self:ifWaittingEnd()
    end

    if self.curStatus == self.Status.Prepare then
        self:ifPrepareEnd()
    end

    if self.curStatus == self.Status.Flying then
        self:ifFlyingEnd()
    end

    if self.curStatus == self.Status.FlyingEnd then
        self:ifStartCreatSafeAreaEnd()
    end

    if self.curStatus == self.Status.WaitShrink then
        self:ifWaitShrinkEnd()
    end

    if self.curStatus == self.Status.Shrinking then
        self:ifShrinkingEnd()
    end

    if self.curStatus == self.Status.WaitSafeArea then
        self:ifStartCreatSafeAreaEnd()
    end

    if self.curStatus == self.Status.WaitGameOver then
        self:ifGameEnd()
    end

    if self.curStatus == self.Status.GameOver then
        self:ifGameOverEnd()
    end

    if self.curStatus == self.Status.WaitClose then
        self:ifWaitCloseEnd()
    end

    if self.IsReviveStage then
        self:ifReviveStageEnd()
    end

    if self:isRunning() then
        self:setPlayerWeaponInfo()
    end
    self:ifRandomWeapon()
    self:setPlayerPoison()
    self:playerOnTick()
end

function ChickenProcess:playerOnTick()
    for _, player in pairs(self.players) do
        player:onTick()
    end
end

function ChickenProcess:ifReviveStageEnd()
    local seconds = GameConfig.canReviveTime - (self.curTick - self.WaitFlyingTick)
    if seconds < 20 and seconds > 0 then
        MsgSender.sendTopTips(2, Messages:msgReviveTip(seconds))
    end

    if seconds <= 0 then
        self.IsReviveStage = false
        local players = PlayerManager:getPlayers()
        for _, player in pairs(players) do
            player:changeClothes("custom_glasses", 9999)
        end
    end
end

function ChickenProcess:ifWaittingEnd()
    --waitting --> prepare
    self:showGameInfo(0)
    if self:ifPlayerEnough() then
        self:waittingEnd()
    else
        if self.curTick % 5 == 0 then
            MsgSender.sendMsg(IMessages:msgWaitPlayer())
            MsgSender.sendMsg(IMessages:msgGamePlayerNum(PlayerManager:getReadyPlayerCount(), GameConfig.startPlayers))
        end
    end
end

function ChickenProcess:ifPrepareEnd()
    if not self:ifPlayerEnough() then
        self.curStatus = self.Status.Waitting
    end

    local seconds = GameConfig.prepareTime - (self.curTick - self.PrepareTick)

    if seconds == 45 or seconds == 30 then
        MsgSender.sendMsg(IMessages:msgGameStartTimeHint(seconds, IMessages.UNIT_SECOND, false))
    end

    if seconds == 10 then
        HostApi.sendStartGame(PlayerManager:getReadyPlayerCount())
    end

    if seconds <= 10 and seconds > 0 then
        MsgSender.sendBottomTips(3, IMessages:msgGameStartTimeHint(seconds, IMessages.UNIT_SECOND, false))
        if seconds <= 3 then
            HostApi.sendPlaySound(0, 12)
        else
            HostApi.sendPlaySound(0, 11)
        end
        if seconds == 1 then
            self:clearAllPlayerInv()
        end
    end

    if seconds <= 0 then
        self:doPrepareEnd()
        local players = PlayerManager:getPlayers()
        ReportUtil:reportGameStart(players[1], self.curTick, PlayerManager:getReadyPlayerCount())
    end
end

function ChickenProcess:doPrepareEnd()
    HostApi.sendGameStatus(0, 1)
    HostApi.sendStartGame(PlayerManager:getReadyPlayerCount())
    self:prepareGame()
    self.curStatus = self.Status.Flying
    self.WaitFlyingTick = self.curTick
    self.RandomWeaponTick = self.curTick
    self.IsReviveStage = true
    self.FlyingTime = AirplaneConfig:getFlyingTime()
    RewardManager:startGame()
    MsgSender.sendMsg(Messages:msgGameStartTip())
    self:showGameInfo(0)
end

function ChickenProcess:prepareGame()
    HostApi.setAutoShootEnable(0, true)
    AirplaneConfig:setAirplane()
    self.playerTotalNum = PlayerManager:getReadyPlayerCount()
    self.players = self:getReadyPlayers()
    for _, player in pairs(self.players) do
        player:initEquipItems()
        GamePacketSender:sendPixelGunChickenWarningSetting(player.rakssid, true,
                GameConfig.shootWarningRange, GameConfig.footWarningRange, GameConfig.weaponWarningRange)
    end
    HostApi.sendChangeAircraftUI(0, false)
    self:showGameInfo(0)
end

function ChickenProcess:ifFlyingEnd()
    local ticks = self.curTick - self.WaitFlyingTick
    local seconds = self.FlyingTime - ticks
    if ticks == 3 then
        HostApi.sendChangeAircraftUI(0, true)
    end
    if seconds <= 3 then
        self:doFlyingEnd()
    end
end

function ChickenProcess:doFlyingEnd()
    self.curStatus = self.Status.FlyingEnd
    self.WaitSafeAreaTick = self.curTick
    EngineWorld:getWorld():tryAllPlayerOffAircraft()
    self.WaitCreatSafeAreaTime = SafeAreaConfig:getWaitCreatTime()
end

function ChickenProcess:ifStartCreatSafeAreaEnd()
    local ticks = self.curTick - self.WaitSafeAreaTick
    local seconds = self.WaitCreatSafeAreaTime - ticks
    if next(self.poison) == nil and next(self.safe) ~= nil then
        MsgSender.sendBottomTips(2, Messages:msgCreatSafe(seconds))
    end

    if seconds <= 0 then
        self:doCreatSafeArea()
    end
end

function ChickenProcess:doCreatSafeArea()
    self.curStatus = self.Status.WaitShrink
    self.WaitShrinkTick = self.curTick
    self.WaitShrinkTime = SafeAreaConfig:getWaitShrinkTime()
    self.safe, self.poison = SafeAreaConfig:creatSafeArea()
    if next(self.poison) == nil then
        return
    end
    EngineWorld:getWorld():setPoisonCircleRange(
            self.safe.startPos,
            self.safe.endPos,
            self.poison.startPos,
            self.poison.endPos, 0)
    self:showGameInfo(self.WaitShrinkTime)

end

function ChickenProcess:ifWaitShrinkEnd()
    local ticks = self.curTick - self.WaitShrinkTick
    local seconds = self.WaitShrinkTime - ticks
    if seconds <= 0 then
        self:doShrinking()
    end
end

function ChickenProcess:doShrinking()
    self.curStatus = self.Status.Shrinking
    self.WaitShrinkEndTick = self.curTick
    self.ShrinkingTime = self.poison.shrinkTime or 0
    if next(self.poison) == nil then
        return
    end
    self.poison:setMoveSpeed(SafeAreaConfig:getSpeed(self.safe, self.poison, self.poison.shrinkTime))
    EngineWorld:getWorld():setPoisonCircleRange(
            self.safe.startPos,
            self.safe.endPos,
            self.poison.startPos,
            self.poison.endPos,
            self.poison.moveSpeed)
    MsgSender.sendBottomTips(self.poison.shrinkTime, Messages:msgIsShringking())
end

function ChickenProcess:ifShrinkingEnd()
    local ticks = self.curTick - self.WaitShrinkEndTick
    local seconds = self.ShrinkingTime - ticks
    if next(self.poison) ~= nil then
        self.poison:onAreaMove(self.safe.startPos, self.safe.endPos)
    end
    if seconds <= 0 then
        self:doShrinkingEnd()
    end
end

function ChickenProcess:doShrinkingEnd()
    if SafeAreaConfig:isLastPoison() then
        self.curStatus = self.Status.WaitGameOver
        self.WaitGameOverTick = self.curTick
        return
    end
    self.curStatus = self.Status.WaitSafeArea
    self.WaitSafeAreaTick = self.curTick
    self.WaitCreatSafeAreaTime = SafeAreaConfig:getWaitCreatTime()
    if next(self.poison) == nil then
        self:showGameInfo(self.WaitCreatSafeAreaTime)
    end
end

function ChickenProcess:ifGameEnd()
    if self:getLifePlayerCount() == 1 then
        self:doWin()
    end
end

function ChickenProcess:doWin()
    self.curStatus = self.Status.GameOver
    self.GameOverTick = self.curTick

    for _, player in pairs(self.players) do
        ChickenSettlement:SendSettlementResult(player, 1, 3, true)
        GamePacketSender:sendPixelGunHideChickenWarning(player.rakssid, 3)
        GamePacketSender:sendPixelGunHideChickenWarning(player.rakssid, 4)
        player.taskController:packingProgressData(player, Define.TaskType.Fright.WinGame, GameMatch.gameType, player.cur_map_id)
        player.taskController:packingProgressData(player, Define.TaskType.Fright.WinAndKill, GameMatch.gameType, player.kills)
        for _, process in pairs(player.taskController.winProgresses) do
            player.taskController:saveTaskProcesses(player, process)
        end
        player.taskController:packingProgressData(player, Define.TaskType.Fright.CompleteGame, GameMatch.gameType, player.cur_map_id)
        ReportUtil:reportDie(player)
        player:resetEquip()
    end

    GamePacketSender:sendShowPixelGunChickenResult(0, "")
    HostApi.sendStartGame(PlayerManager:getPlayerCount())
end

function ChickenProcess:startFly()
    return self.curStatus >= self.Status.Flying
end

function ChickenProcess:hasPoisonArea()
    if next(self.poison) ~= nil then
        return true
    end
    return false
end

function ChickenProcess:getPoisonArea()
    return self.poison
end

function ChickenProcess:setPlayerPoison()
    for _, player in pairs(self.players) do
        if player.isInPoison then
            player:subHealth(self.poison.bleedValue)
        end
    end
end

function ChickenProcess:setPlayerInfo(player)
    player.maxHealth = player.maxHealth + GameConfig.healthValue
    player:setHealth(player.maxHealth)
    player:changeMaxHealth(player.maxHealth)
    player.maxDefense = player.curDefense + GameConfig.defenseValue
    player.curDefense = 0
    player:updateDefense()
    player.cur_map_id = GameConfig.mapId
    local item = {}
    item.equip_guns = TableUtil.copyTable(player.equip_guns)
    item.equip_props = TableUtil.copyTable(player.equip_props)
    item.equip_blocks = TableUtil.copyTable(player.equip_blocks)
    player.original_equip = item
    player.equip_props = {}
    self:setEquipWeaponInfo(player, player.equip_guns)
end

function ChickenProcess:setEquipWeaponInfo(player, equipItems)
    player.equip_props = {}
    if equipItems == nil then
        return
    end
    player.equip_guns = TableUtil.copyTable(equipItems)
    for type, equip_gun in pairs(player.equip_guns) do
        if tonumber(type) ~= GunConfig.Type.CloseIn then
            player.equip_guns[type] = nil
        else
            player.equip_guns[type].AddDamage = 0
            local item = GunConfig:getGunByItemId(equip_gun.ItemId)
            if item then
                player.equip_guns[type].PropertyIds = item.propertyIds
            end
        end
    end
end

function ChickenProcess:assignTeam(player)
    if not self:ifPlayerCanLogin() then
        HostApi.sendGameover(player.rakssid, IMessages:msgGameHasStarting(), GameOverCode.GameStarted)
        return
    end
    player:setTeamId(self.Index)
    self.Index = self.Index + 1
end

function ChickenProcess:onPlayerDie(killer, dier)
    if dier.killByPoison then
        dier.killByPoison = false
        MsgSender.sendKillMsg("", dier.name, 0, 0, 0, TextFormat.colorAqua, 1)
    end
    if self.IsReviveStage then
        if killer ~= nil then
            dier:onDie(false, true)
            dier:sendReviveData(killer, true)
        else
            RespawnHelper.sendRespawnCountdown(dier, GameConfig.autoRespawnTime)
            dier:onDie(false, false)
        end
        self:setDieBox(dier)
    else
        dier:onDie(false, false)
        self:setDieBox(dier)
        self:subPlayer(dier.rakssid)
        dier:resetEquip()
        dier:setAllowFlying(true)
        HostApi.sendSetFlying(dier.rakssid)
        local rank = self:getLifePlayerCount() + 1
        ChickenSettlement:SendSettlementResult(dier, rank, 0, false)
        GamePacketSender:sendPixelGunHideChickenWarning(dier.rakssid, 4)
        GamePacketSender:sendPixelGunChickenWarningSetting(dier.rakssid, false,
                GameConfig.shootWarningRange, GameConfig.footWarningRange, GameConfig.weaponWarningRange)
        dier.taskController:packingProgressData(dier, Define.TaskType.Fright.CompleteGame, GameMatch.gameType, dier.cur_map_id)
        ReportUtil:reportDie(dier)
    end
end

function ChickenProcess:getLifePlayerCount()
    return #self.players
end

function ChickenProcess:subPlayer(rakssid)
    for index, _player in pairs(self.players) do
        if _player.rakssid == rakssid then
            table.remove(self.players, index)
            break
        end
    end
    self:showGameInfo(0)
    if self:isRunning() then
        self:ifGameEnd()
    end
end

function ChickenProcess:canRespawn()
    return self.IsReviveStage
end

function ChickenProcess:onPlayerRespawn(player)
    GamePacketSender:sendPixelGunReviveData(player.rakssid, false, "{}")
    LuaTimer:cancel(player.respawnTaskKey)
    player.respawnTaskKey = ""
    player.invincibleTime = GameConfig.invincibleTime
    player.isFlyInvincible = true
    player.isLife = true
    player:setHealth(player.maxHealth)
    player:changeMaxHealth(player.maxHealth)
    player.curDefense = 0
    player:updateDefense()
    player:sendNameToOtherPlayers()
    self:setEquipWeaponInfo(player, player.original_equip.equip_guns)
    self.equip_blocks = player.original_equip.equip_blocks
    player:initEquipItems()
    player:resetCurrentItem()
    self:teleGamePos(player)
end

function ChickenProcess:teleGamePos(player)
    if not SafeAreaConfig:isLastArea() then
        local safe = SafeAreaConfig:getCurAreaId()
        local respawn = RespawnConfig:ChickenRandomRespawn(tonumber(safe))
        player:teleportPosWithYaw(respawn.position, respawn.yaw)
        HostApi.sendChangeAircraftUI(player.rakssid, true)
        player.isParachute = false
        player.changeWing = false
    end
end

function ChickenProcess:setDieBox(player)
    if player == nil then
        return
    end
    local pos = player:getPosition()
    local positions = self:getDieBoxPos(pos)
    local index = 1
    for type, gun in pairs(player.equip_guns) do
        if tonumber(type) ~= GunConfig.Type.CloseIn then
            local config = {
                id = player:getEntityId() * 10 + tonumber(type),
                pos = positions[index]
            }
            WeaponSupply.new(config, gun.ItemId, 1000)
            index = index + 1
        end
    end
    local config = SupplyConfig:randomDieSupply()
    if not config then
        return
    end
    config = TableUtil.copyTable(config)
    config.position = positions[index]
    SupplyPoint.new(config)
end

function ChickenProcess:showGameInfo(time)
    local players = PlayerManager:getPlayers()
    local data = {}
    if self:isGameBegin() then
        data.Survive = tostring(self:getLifePlayerCount())
    else
        data.Survive = tostring(PlayerManager:getReadyPlayerCount())
    end
    if time > 0 then
        data.Poison = time * 1000
    end

    if self:isGameBegin() and self.IsReviveStage then
        data.Revive = GameConfig.canReviveTime * 1000
    end

    for _, player in pairs(players) do
        if player:checkReady() then
            data.Kill = tostring(player.kills)
            GamePacketSender:sendPixelGunChickenGameData(player.rakssid, json.encode(data))
        end
    end
end

function ChickenProcess:getDieBoxPos(pos)
    local result = {}
    local range = 1.5
    table.insert(result, pos)
    table.insert(result, VectorUtil.newVector3(pos.x + range, pos.y, pos.z))
    table.insert(result, VectorUtil.newVector3(pos.x - range, pos.y, pos.z))
    table.insert(result, VectorUtil.newVector3(pos.x, pos.y, pos.z + range))
    table.insert(result, VectorUtil.newVector3(pos.x, pos.y, pos.z - range))
    return result
end

function ChickenProcess:isRunning(...)
    return self.curStatus > self.Status.Prepare
            and self.curStatus < self.Status.GameOver
end

function ChickenProcess:isGameOver(player)
    return self.curStatus > self.Status.WaitSafeArea
end

function ChickenProcess:onPlayerQuit(player)
    self:subPlayer(player.rakssid)
    player:resetEquip()
    if self:isGameBegin() and player.isReward == false then
        SeasonManager:addUserHonor(player.userId, GameConfig.quitSubHonor, player.level)
        ReportUtil:reportDie(player)
    end
    self:ifClose()
end

function ChickenProcess:buildShowName(player, same)
    local nameList = {}

    local disName = player.name
    if same then
        if BaseMain:isChina() then
            disName = TextFormat.colorBlue .. disName
        else
            disName = TextFormat.colorBlue .. disName
        end
    else
        if BaseMain:isChina() then
            disName = TextFormat.colorRed .. disName
        else
            disName = TextFormat.colorRed .. disName
        end
    end
    if player:isGameVip() then
        if BaseMain:isChina() then
            disName = TextFormat.colorGold .. "[会员]" .. disName
        else
            disName = TextFormat.colorGold .. "[VIP]" .. disName
        end
    end
    PlayerIdentityCache:buildNameList(player.userId, nameList, disName)
    return table.concat(nameList, "\n")
end

function ChickenProcess:ifPlayerCanLogin()
    return not self:isGameBegin()
end

function ChickenProcess:ifRandomWeapon()
    if WeaponSupplyConfig:getRandomTimes() >= #GameConfig.randomWeaponTime + 1 or self.RandomWeaponTick == 0 then
        return
    end

    local times = WeaponSupplyConfig:getRandomTimes()
    local time = tonumber(GameConfig.randomWeaponTime[times])
    local ticks = self.curTick - self.RandomWeaponTick
    local seconds = time - ticks
    if seconds <= 0 then
        WeaponSupplyConfig:randomSupply(times + 1)
        self.RandomWeaponTick = self.curTick
    end
end

function ChickenProcess:setPlayerWeaponInfo()
    for _, player in pairs(self.players) do
        player:setWeaponInfo()
    end
end

return ChickenProcess